"""
Parameterized generator for GH1093_spaCy_8012.

Source PR:    https://github.com/explosion/spaCy/pull/8012
Source Issue: N/A

Seed varies: renames 'accumulate_gradient' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1093_spaCy_8012'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1093_spaCy_8012'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accumulate_gradient', 'accumulate_gradient' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1093_spaCy_8012',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'explosion/spaCy',
                "pr_number": 8012,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/explosion/spaCy/pull/8012",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'spacy/pipeline/tok2vec.py': 'from typing import Sequence, Iterable, Optional, Dict, Callable, List\nfrom thinc.api import Model, set_dropout_rate, Optimizer, Config\nfrom itertools import islice\n\nfrom .trainable_pipe import TrainablePipe\nfrom ..training import Example, validate_examples, validate_get_examples\nfrom ..tokens import Doc\nfrom ..vocab import Vocab\nfrom ..language import Language\nfrom ..errors import Errors\n\ndefault_model_config = """\n[model]\n@architectures = "spacy.HashEmbedCNN.v2"\npretrained_vectors = null\nwidth = 96\ndepth = 4\nembed_size = 2000\nwindow_size = 1\nmaxout_pieces = 3\nsubword_features = true\n"""\nDEFAULT_TOK2VEC_MODEL = Config().from_str(default_model_config)["model"]\n\n\n@Language.factory(\n    "tok2vec", assigns=["doc.tensor"], default_config={"model": DEFAULT_TOK2VEC_MODEL}\n)\ndef make_tok2vec(nlp: Language, name: str, model: Model) -> "Tok2Vec":\n    return Tok2Vec(nlp.vocab, model, name)\n\n\nclass Tok2Vec(TrainablePipe):\n    """Apply a "token-to-vector" model and set its outputs in the doc.tensor\n    attribute. This is mostly useful to share a single subnetwork between multiple\n    components, e.g. to have one embedding and CNN network shared between a\n    parser, tagger and NER.\n\n    In order to use the `Tok2Vec` predictions, subsequent components should use\n    the `Tok2VecListener` layer as the tok2vec subnetwork of their model. This\n    layer will read data from the `doc.tensor` attribute during prediction.\n    During training, the `Tok2Vec` component will save its prediction and backprop\n    callback for each batch, so that the subsequent components can backpropagate\n    to the shared weights. This implementation is used because it allows us to\n    avoid relying on object identity within the models to achieve the parameter\n    sharing.\n    """\n\n    def __init__(self, vocab: Vocab, model: Model, name: str = "tok2vec") -> None:\n        """Initialize a tok2vec component.\n\n        vocab (Vocab): The shared vocabulary.\n        model (thinc.api.Model[List[Doc], List[Floats2d]]):\n            The Thinc Model powering the pipeline component. It should take\n            a list of Doc objects as input, and output a list of 2d float arrays.\n        name (str): The component instance name.\n\n        DOCS: https://spacy.io/api/tok2vec#init\n        """\n        self.vocab = vocab\n        self.model = model\n        self.name = name\n        self.listener_map = {}\n        self.cfg = {}\n\n    @property\n    def listeners(self) -> List["Tok2VecListener"]:\n        """RETURNS (List[Tok2VecListener]): The listener models listening to this\n        component. Usually internals.\n        """\n        return [m for c in self.listening_components for m in self.listener_map[c]]\n\n    @property\n    def listening_components(self) -> List[str]:\n        """RETURNS (List[str]): The downstream components listening to this\n        component. Usually internals.\n        """\n        return list(self.listener_map.keys())\n\n    def add_listener(self, listener: "Tok2VecListener", component_name: str) -> None:\n        """Add a listener for a downstream component. Usually internals."""\n        self.listener_map.setdefault(component_name, [])\n        if listener not in self.listener_map[component_name]:\n            self.listener_map[component_name].append(listener)\n\n    def remove_listener(self, listener: "Tok2VecListener", component_name: str) -> bool:\n        """Remove a listener for a downstream component. Usually internals."""\n        if component_name in self.listener_map:\n            if listener in self.listener_map[component_name]:\n                self.listener_map[component_name].remove(listener)\n                # If no listeners are left, remove entry\n                if not self.listener_map[component_name]:\n                    del self.listener_map[component_name]\n                return True\n        return False\n\n    def find_listeners(self, component) -> None:\n        """Walk over a model of a processing component, looking for layers that\n        are Tok2vecListener subclasses that have an upstream_name that matches\n        this component. Listeners can also set their upstream_name attribute to\n        the wildcard string \'*\' to match any `Tok2Vec`.\n\n        You\'re unlikely to ever need multiple `Tok2Vec` components, so it\'s\n        fine to leave your listeners upstream_name on \'*\'.\n        """\n        names = ("*", self.name)\n        if isinstance(getattr(component, "model", None), Model):\n            for node in component.model.walk():\n                if isinstance(node, Tok2VecListener) and node.upstream_name in names:\n                    self.add_listener(node, component.name)\n\n    def predict(self, docs: Iterable[Doc]):\n        """Apply the pipeline\'s model to a batch of docs, without modifying them.\n        Returns a single tensor for a batch of documents.\n\n        docs (Iterable[Doc]): The documents to predict.\n        RETURNS: Vector representations for each token in the documents.\n\n        DOCS: https://spacy.io/api/tok2vec#predict\n        """\n        tokvecs = self.model.predict(docs)\n        batch_id = Tok2VecListener.get_batch_id(docs)\n        for listener in self.listeners:\n            listener.receive(batch_id, tokvecs, _empty_backprop)\n        return tokvecs\n\n    def set_annotations(self, docs: Sequence[Doc], tokvecses) -> None:\n        """Modify a batch of documents, using pre-computed scores.\n\n        docs (Iterable[Doc]): The documents to modify.\n        tokvecses: The tensors to set, produced by Tok2Vec.predict.\n\n        DOCS: https://spacy.io/api/tok2vec#set_annotations\n        """\n        for doc, tokvecs in zip(docs, tokvecses):\n            assert tokvecs.shape[0] == len(doc)\n            doc.tensor = tokvecs\n\n    def update(\n        self,\n        examples: Iterable[Example],\n        *,\n        drop: float = 0.0,\n        sgd: Optional[Optimizer] = None,\n        losses: Optional[Dict[str, float]] = None,\n    ):\n        """Learn from a batch of documents and gold-standard information,\n        updating the pipe\'s model.\n\n        examples (Iterable[Example]): A batch of Example objects.\n        drop (float): The dropout rate.\n        sgd (thinc.api.Optimizer): The optimizer.\n        losses (Dict[str, float]): Optional record of the loss during training.\n            Updated using the component name as the key.\n        RETURNS (Dict[str, float]): The updated losses dictionary.\n\n        DOCS: https://spacy.io/api/tok2vec#update\n        """\n        if losses is None:\n            losses = {}\n        validate_examples(examples, "Tok2Vec.update")\n        docs = [eg.predicted for eg in examples]\n        set_dropout_rate(self.model, drop)\n        tokvecs, bp_tokvecs = self.model.begin_update(docs)\n        d_tokvecs = [self.model.ops.alloc2f(*t2v.shape) for t2v in tokvecs]\n        losses.setdefault(self.name, 0.0)\n\n        def accumulate_gradient(one_d_tokvecs):\n            """Accumulate tok2vec loss and gradient. This is passed as a callback\n            to all but the last listener. Only the last one does the backprop.\n            """\n            nonlocal d_tokvecs\n            for i in range(len(one_d_tokvecs)):\n                d_tokvecs[i] += one_d_tokvecs[i]\n                losses[self.name] += float((one_d_tokvecs[i] ** 2).sum())\n\n        def backprop(one_d_tokvecs):\n            """Callback to actually do the backprop. Passed to last listener."""\n            accumulate_gradient(one_d_tokvecs)\n            d_docs = bp_tokvecs(d_tokvecs)\n            if sgd is not None:\n                self.finish_update(sgd)\n            return d_docs\n\n        batch_id = Tok2VecListener.get_batch_id(docs)\n        for listener in self.listeners[:-1]:\n            listener.receive(batch_id, tokvecs, accumulate_gradient)\n        if self.listeners:\n            self.listeners[-1].receive(batch_id, tokvecs, backprop)\n        return losses\n\n    def get_loss(self, examples, scores) -> None:\n        pass\n\n    def initialize(\n        self,\n        get_examples: Callable[[], Iterable[Example]],\n        *,\n        nlp: Optional[Language] = None,\n    ):\n        """Initialize the pipe for training, using a representative set\n        of data examples.\n\n        get_examples (Callable[[], Iterable[Example]]): Function that\n            returns a representative sample of gold-standard Example objects.\n        nlp (Language): The current nlp object the component is part of.\n\n        DOCS: https://spacy.io/api/tok2vec#initialize\n        """\n        validate_get_examples(get_examples, "Tok2Vec.initialize")\n        doc_sample = []\n        for example in islice(get_examples(), 10):\n            doc_sample.append(example.x)\n        assert doc_sample, Errors.E923.format(name=self.name)\n        self.model.initialize(X=doc_sample)\n\n    def add_label(self, label):\n        raise NotImplementedError\n\n\nclass Tok2VecListener(Model):\n    """A layer that gets fed its answers from an upstream connection,\n    for instance from a component earlier in the pipeline.\n\n    The Tok2VecListener layer is used as a sublayer within a component such\n    as a parser, NER or text categorizer. Usually you\'ll have multiple listeners\n    connecting to a single upstream Tok2Vec component, that\'s earlier in the\n    pipeline. The Tok2VecListener layers act as proxies, passing the predictions\n    from the Tok2Vec component into downstream components, and communicating\n    gradients back upstream.\n    """\n\n    name = "tok2vec-listener"\n\n    def __init__(self, upstream_name: str, width: int) -> None:\n        """\n        upstream_name (str): A string to identify the \'upstream\' Tok2Vec component\n            to communicate with. The upstream name should either be the wildcard\n            string \'*\', or the name of the `Tok2Vec` component. You\'ll almost\n            never have multiple upstream Tok2Vec components, so the wildcard\n            string will almost always be fine.\n        width (int):\n            The width of the vectors produced by the upstream tok2vec component.\n        """\n        Model.__init__(self, name=self.name, forward=forward, dims={"nO": width})\n        self.upstream_name = upstream_name\n        self._batch_id = None\n        self._outputs = None\n        self._backprop = None\n\n    @classmethod\n    def get_batch_id(cls, inputs: List[Doc]) -> int:\n        """Calculate a content-sensitive hash of the batch of documents, to check\n        whether the next batch of documents is unexpected.\n        """\n        return sum(sum(token.orth for token in doc) for doc in inputs)\n\n    def receive(self, batch_id: int, outputs, backprop) -> None:\n        """Store a batch of training predictions and a backprop callback. The\n        predictions and callback are produced by the upstream Tok2Vec component,\n        and later will be used when the listener\'s component\'s model is called.\n        """\n        self._batch_id = batch_id\n        self._outputs = outputs\n        self._backprop = backprop\n\n    def verify_inputs(self, inputs) -> bool:\n        """Check that the batch of Doc objects matches the ones we have a\n        prediction for.\n        """\n        if self._batch_id is None and self._outputs is None:\n            raise ValueError(Errors.E954)\n        else:\n            batch_id = self.get_batch_id(inputs)\n            if batch_id != self._batch_id:\n                raise ValueError(Errors.E953.format(id1=batch_id, id2=self._batch_id))\n            else:\n                return True\n\n\ndef forward(model: Tok2VecListener, inputs, is_train: bool):\n    """Supply the outputs from the upstream Tok2Vec component."""\n    if is_train:\n        model.verify_inputs(inputs)\n        return model._outputs, model._backprop\n    else:\n        # This is pretty grim, but it\'s hard to do better :(.\n        # It\'s hard to avoid relying on the doc.tensor attribute, because the\n        # pipeline components can batch the data differently during prediction.\n        # That doesn\'t happen in update, where the nlp object works on batches\n        # of data.\n        # When the components batch differently, we don\'t receive a matching\n        # prediction from the upstream, so we can\'t predict.\n        outputs = []\n        width = model.get_dim("nO")\n        for doc in inputs:\n            if doc.tensor.size == 0:\n                # But we do need to do *something* if the tensor hasn\'t been set.\n                # The compromise is to at least return data of the right shape,\n                # so the output is valid.\n                outputs.append(model.ops.alloc2f(len(doc), width))\n            else:\n                outputs.append(doc.tensor)\n        return outputs, lambda dX: []\n\n\ndef _empty_backprop(dX):  # for pickling\n    return []\n',
            'spacy/tests/pipeline/test_tok2vec.py': 'import pytest\nfrom spacy.ml.models.tok2vec import build_Tok2Vec_model\nfrom spacy.ml.models.tok2vec import MultiHashEmbed, CharacterEmbed\nfrom spacy.ml.models.tok2vec import MishWindowEncoder, MaxoutWindowEncoder\nfrom spacy.pipeline.tok2vec import Tok2Vec, Tok2VecListener\nfrom spacy.vocab import Vocab\nfrom spacy.tokens import Doc\nfrom spacy.training import Example\nfrom spacy import util\nfrom spacy.lang.en import English\nfrom thinc.api import Config, get_current_ops\nfrom numpy.testing import assert_array_equal\n\nfrom ..util import get_batch, make_tempdir\n\n\ndef test_empty_doc():\n    width = 128\n    embed_size = 2000\n    vocab = Vocab()\n    doc = Doc(vocab, words=[])\n    tok2vec = build_Tok2Vec_model(\n        MultiHashEmbed(\n            width=width,\n            rows=[embed_size, embed_size, embed_size, embed_size],\n            include_static_vectors=False,\n            attrs=["NORM", "PREFIX", "SUFFIX", "SHAPE"],\n        ),\n        MaxoutWindowEncoder(width=width, depth=4, window_size=1, maxout_pieces=3),\n    )\n    tok2vec.initialize()\n    vectors, backprop = tok2vec.begin_update([doc])\n    assert len(vectors) == 1\n    assert vectors[0].shape == (0, width)\n\n\n@pytest.mark.parametrize(\n    "batch_size,width,embed_size", [[1, 128, 2000], [2, 128, 2000], [3, 8, 63]]\n)\ndef test_tok2vec_batch_sizes(batch_size, width, embed_size):\n    batch = get_batch(batch_size)\n    tok2vec = build_Tok2Vec_model(\n        MultiHashEmbed(\n            width=width,\n            rows=[embed_size] * 4,\n            include_static_vectors=False,\n            attrs=["NORM", "PREFIX", "SUFFIX", "SHAPE"],\n        ),\n        MaxoutWindowEncoder(width=width, depth=4, window_size=1, maxout_pieces=3),\n    )\n    tok2vec.initialize()\n    vectors, backprop = tok2vec.begin_update(batch)\n    assert len(vectors) == len(batch)\n    for doc_vec, doc in zip(vectors, batch):\n        assert doc_vec.shape == (len(doc), width)\n\n\n@pytest.mark.parametrize(\n    "width,embed_arch,embed_config,encode_arch,encode_config",\n    # fmt: off\n    [\n        (8, MultiHashEmbed, {"rows": [100, 100], "attrs": ["SHAPE", "LOWER"], "include_static_vectors": False}, MaxoutWindowEncoder, {"window_size": 1, "maxout_pieces": 3, "depth": 2}),\n        (8, MultiHashEmbed, {"rows": [100, 20], "attrs": ["ORTH", "PREFIX"], "include_static_vectors": False}, MishWindowEncoder, {"window_size": 1, "depth": 6}),\n        (8, CharacterEmbed, {"rows": 100, "nM": 64, "nC": 8, "include_static_vectors": False}, MaxoutWindowEncoder, {"window_size": 1, "maxout_pieces": 3, "depth": 3}),\n        (8, CharacterEmbed, {"rows": 100, "nM": 16, "nC": 2, "include_static_vectors": False}, MishWindowEncoder, {"window_size": 1, "depth": 3}),\n    ],\n    # fmt: on\n)\ndef test_tok2vec_configs(width, embed_arch, embed_config, encode_arch, encode_config):\n    embed_config["width"] = width\n    encode_config["width"] = width\n    docs = get_batch(3)\n    tok2vec = build_Tok2Vec_model(\n        embed_arch(**embed_config), encode_arch(**encode_config)\n    )\n    tok2vec.initialize(docs)\n    vectors, backprop = tok2vec.begin_update(docs)\n    assert len(vectors) == len(docs)\n    assert vectors[0].shape == (len(docs[0]), width)\n    backprop(vectors)\n\n\ndef test_init_tok2vec():\n    # Simple test to initialize the default tok2vec\n    nlp = English()\n    tok2vec = nlp.add_pipe("tok2vec")\n    assert tok2vec.listeners == []\n    nlp.initialize()\n    assert tok2vec.model.get_dim("nO")\n\n\ncfg_string = """\n    [nlp]\n    lang = "en"\n    pipeline = ["tok2vec","tagger"]\n\n    [components]\n\n    [components.tagger]\n    factory = "tagger"\n\n    [components.tagger.model]\n    @architectures = "spacy.Tagger.v1"\n    nO = null\n\n    [components.tagger.model.tok2vec]\n    @architectures = "spacy.Tok2VecListener.v1"\n    width = ${components.tok2vec.model.encode.width}\n\n    [components.tok2vec]\n    factory = "tok2vec"\n\n    [components.tok2vec.model]\n    @architectures = "spacy.Tok2Vec.v2"\n\n    [components.tok2vec.model.embed]\n    @architectures = "spacy.MultiHashEmbed.v1"\n    width = ${components.tok2vec.model.encode.width}\n    rows = [2000, 1000, 1000, 1000]\n    attrs = ["NORM", "PREFIX", "SUFFIX", "SHAPE"]\n    include_static_vectors = false\n\n    [components.tok2vec.model.encode]\n    @architectures = "spacy.MaxoutWindowEncoder.v2"\n    width = 96\n    depth = 4\n    window_size = 1\n    maxout_pieces = 3\n    """\n\nTRAIN_DATA = [\n    ("I like green eggs", {"tags": ["N", "V", "J", "N"]}),\n    ("Eat blue ham", {"tags": ["V", "J", "N"]}),\n]\n\n\ndef test_tok2vec_listener():\n    orig_config = Config().from_str(cfg_string)\n    nlp = util.load_model_from_config(orig_config, auto_fill=True, validate=True)\n    assert nlp.pipe_names == ["tok2vec", "tagger"]\n    tagger = nlp.get_pipe("tagger")\n    tok2vec = nlp.get_pipe("tok2vec")\n    tagger_tok2vec = tagger.model.get_ref("tok2vec")\n    assert isinstance(tok2vec, Tok2Vec)\n    assert isinstance(tagger_tok2vec, Tok2VecListener)\n    train_examples = []\n    for t in TRAIN_DATA:\n        train_examples.append(Example.from_dict(nlp.make_doc(t[0]), t[1]))\n        for tag in t[1]["tags"]:\n            tagger.add_label(tag)\n\n    # Check that the Tok2Vec component finds it listeners\n    assert tok2vec.listeners == []\n    optimizer = nlp.initialize(lambda: train_examples)\n    assert tok2vec.listeners == [tagger_tok2vec]\n\n    for i in range(5):\n        losses = {}\n        nlp.update(train_examples, sgd=optimizer, losses=losses)\n\n    doc = nlp("Running the pipeline as a whole.")\n    doc_tensor = tagger_tok2vec.predict([doc])[0]\n    ops = get_current_ops()\n    assert_array_equal(ops.to_numpy(doc.tensor), ops.to_numpy(doc_tensor))\n\n    # TODO: should this warn or error?\n    nlp.select_pipes(disable="tok2vec")\n    assert nlp.pipe_names == ["tagger"]\n    nlp("Running the pipeline with the Tok2Vec component disabled.")\n\n\ndef test_tok2vec_listener_callback():\n    orig_config = Config().from_str(cfg_string)\n    nlp = util.load_model_from_config(orig_config, auto_fill=True, validate=True)\n    assert nlp.pipe_names == ["tok2vec", "tagger"]\n    tagger = nlp.get_pipe("tagger")\n    tok2vec = nlp.get_pipe("tok2vec")\n    nlp._link_components()\n    docs = [nlp.make_doc("A random sentence")]\n    tok2vec.model.initialize(X=docs)\n    gold_array = [[1.0 for tag in ["V", "Z"]] for word in docs]\n    label_sample = [tagger.model.ops.asarray(gold_array, dtype="float32")]\n    tagger.model.initialize(X=docs, Y=label_sample)\n    docs = [nlp.make_doc("Another entirely random sentence")]\n    tok2vec.update([Example.from_dict(x, {}) for x in docs])\n    Y, get_dX = tagger.model.begin_update(docs)\n    # assure that the backprop call works (and doesn\'t hit a \'None\' callback)\n    assert get_dX(Y) is not None\n\n\ndef test_replace_listeners():\n    orig_config = Config().from_str(cfg_string)\n    nlp = util.load_model_from_config(orig_config, auto_fill=True, validate=True)\n    examples = [Example.from_dict(nlp.make_doc("x y"), {"tags": ["V", "Z"]})]\n    nlp.initialize(lambda: examples)\n    tok2vec = nlp.get_pipe("tok2vec")\n    tagger = nlp.get_pipe("tagger")\n    assert isinstance(tagger.model.layers[0], Tok2VecListener)\n    assert tok2vec.listener_map["tagger"][0] == tagger.model.layers[0]\n    assert (\n        nlp.config["components"]["tok2vec"]["model"]["@architectures"]\n        == "spacy.Tok2Vec.v2"\n    )\n    assert (\n        nlp.config["components"]["tagger"]["model"]["tok2vec"]["@architectures"]\n        == "spacy.Tok2VecListener.v1"\n    )\n    nlp.replace_listeners("tok2vec", "tagger", ["model.tok2vec"])\n    assert not isinstance(tagger.model.layers[0], Tok2VecListener)\n    t2v_cfg = nlp.config["components"]["tok2vec"]["model"]\n    assert t2v_cfg["@architectures"] == "spacy.Tok2Vec.v2"\n    assert nlp.config["components"]["tagger"]["model"]["tok2vec"] == t2v_cfg\n    with pytest.raises(ValueError):\n        nlp.replace_listeners("invalid", "tagger", ["model.tok2vec"])\n    with pytest.raises(ValueError):\n        nlp.replace_listeners("tok2vec", "parser", ["model.tok2vec"])\n    with pytest.raises(ValueError):\n        nlp.replace_listeners("tok2vec", "tagger", ["model.yolo"])\n    with pytest.raises(ValueError):\n        nlp.replace_listeners("tok2vec", "tagger", ["model.tok2vec", "model.yolo"])\n\n\ncfg_string_multi = """\n    [nlp]\n    lang = "en"\n    pipeline = ["tok2vec","tagger", "ner"]\n\n    [components]\n\n    [components.tagger]\n    factory = "tagger"\n\n    [components.tagger.model]\n    @architectures = "spacy.Tagger.v1"\n    nO = null\n\n    [components.tagger.model.tok2vec]\n    @architectures = "spacy.Tok2VecListener.v1"\n    width = ${components.tok2vec.model.encode.width}\n\n    [components.ner]\n    factory = "ner"\n\n    [components.ner.model]\n    @architectures = "spacy.TransitionBasedParser.v2"\n\n    [components.ner.model.tok2vec]\n    @architectures = "spacy.Tok2VecListener.v1"\n    width = ${components.tok2vec.model.encode.width}\n\n    [components.tok2vec]\n    factory = "tok2vec"\n\n    [components.tok2vec.model]\n    @architectures = "spacy.Tok2Vec.v2"\n\n    [components.tok2vec.model.embed]\n    @architectures = "spacy.MultiHashEmbed.v1"\n    width = ${components.tok2vec.model.encode.width}\n    rows = [2000, 1000, 1000, 1000]\n    attrs = ["NORM", "PREFIX", "SUFFIX", "SHAPE"]\n    include_static_vectors = false\n\n    [components.tok2vec.model.encode]\n    @architectures = "spacy.MaxoutWindowEncoder.v2"\n    width = 96\n    depth = 4\n    window_size = 1\n    maxout_pieces = 3\n    """\n\n\ndef test_replace_listeners_from_config():\n    orig_config = Config().from_str(cfg_string_multi)\n    nlp = util.load_model_from_config(orig_config, auto_fill=True)\n    annots = {"tags": ["V", "Z"], "entities": [(0, 1, "A"), (1, 2, "B")]}\n    examples = [Example.from_dict(nlp.make_doc("x y"), annots)]\n    nlp.initialize(lambda: examples)\n    tok2vec = nlp.get_pipe("tok2vec")\n    tagger = nlp.get_pipe("tagger")\n    ner = nlp.get_pipe("ner")\n    assert tok2vec.listening_components == ["tagger", "ner"]\n    assert any(isinstance(node, Tok2VecListener) for node in ner.model.walk())\n    assert any(isinstance(node, Tok2VecListener) for node in tagger.model.walk())\n    with make_tempdir() as dir_path:\n        nlp.to_disk(dir_path)\n        base_model = str(dir_path)\n        new_config = {\n            "nlp": {"lang": "en", "pipeline": ["tok2vec", "tagger", "ner"]},\n            "components": {\n                "tok2vec": {"source": base_model},\n                "tagger": {\n                    "source": base_model,\n                    "replace_listeners": ["model.tok2vec"],\n                },\n                "ner": {"source": base_model},\n            },\n        }\n        new_nlp = util.load_model_from_config(new_config, auto_fill=True)\n    new_nlp.initialize(lambda: examples)\n    tok2vec = new_nlp.get_pipe("tok2vec")\n    tagger = new_nlp.get_pipe("tagger")\n    ner = new_nlp.get_pipe("ner")\n    assert tok2vec.listening_components == ["ner"]\n    assert any(isinstance(node, Tok2VecListener) for node in ner.model.walk())\n    assert not any(isinstance(node, Tok2VecListener) for node in tagger.model.walk())\n    t2v_cfg = new_nlp.config["components"]["tok2vec"]["model"]\n    assert t2v_cfg["@architectures"] == "spacy.Tok2Vec.v2"\n    assert new_nlp.config["components"]["tagger"]["model"]["tok2vec"] == t2v_cfg\n    assert (\n        new_nlp.config["components"]["ner"]["model"]["tok2vec"]["@architectures"]\n        == "spacy.Tok2VecListener.v1"\n    )\n',
        }
